class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def filter_text(self, text, replacement_char='*'):
        if not text:
            return ""

        filtered_chars = list(text)
        n = len(text)

        i = 0
        while i < n:
            node = self.root
            longest_match_len = 0
            match_end_index = -1

            j = i
            while j < n:
                char = text[j].lower()

                if char not in node.children:
                    break

                node = node.children[char]

                if node.is_end_of_word:
                    longest_match_len = j - i + 1
                    match_end_index = j

                j += 1

            if longest_match_len > 0:
                for k in range(i, match_end_index + 1):
                    filtered_chars[k] = replacement_char
                i = match_end_index + 1
            else:
                i += 1

        return "".join(filtered_chars)
